  'float N(float t){return fract(sin(t*12345.564)*7658.76);}',
  'float Saw(float b,float t){return S(0.,b,t)*S(1.,b,t);}',
  'vec2 DropLayer2(vec2 uv,float t){vec2 UV=uv;uv.y+=t*0.75;vec2 a=vec2(6.,1.);vec2 grid=a*2.;vec2 id=floor(uv*grid);float cs=N(id.x);uv.y+=cs;id=floor(uv*grid);vec3 n=N13(id.x*35.2+id.y*2376.1);vec2 st=fract(uv*grid)-vec2(.5,0);float x=n.x-.5;float y=UV.y*20.;float wig=sin(y+sin(y));x+=wig*(.5-abs(x))*(n.z-.5);x*=.7;float ti=fract(t+n.z);y=(Saw(.85,ti)-.5)*.9+.5;vec2 p=vec2(x,y);float d=length((st-p)*a.yx);float md=S(.4,.0,d);float r=sqrt(S(1.,y,st.y));float cd=abs(st.x-x);float trail=S(.23*r,.15*r*r,cd);float tf=S(-.02,.02,st.y-y);trail*=tf*r*r;y=UV.y;float t2=S(.2*r,.0,cd);float dr=max(0.,(sin(y*(1.-y)*120.)-st.y))*t2*tf*n.z;y=fract(y*10.)+(st.y-.5);float dd=length(st-vec2(x,y));dr=S(.3,0.,dd);float m=md+dr*r*tf;return vec2(m,trail);}',
  'float StaticDrops(vec2 uv,float t){uv*=40.;vec2 id=floor(uv);uv=fract(uv)-.5;vec3 n=N13(id.x*107.45+id.y*3543.654);vec2 p=(n.xy-.5)*.7;float d=length(uv-p);float fade=Saw(.025,fract(t+n.z));float c=S(.3,0.,d)*fract(n.z*10.)*fade;return c;}',
  'vec2 Drops(vec2 uv,float t,float l0,float l1,float l2){float s=StaticDrops(uv,t)*l0;vec2 m1=DropLayer2(uv,t)*l1;vec2 m2=DropLayer2(uv*1.85,t)*l2;float c=s+m1.x+m2.x;c=S(.3,1.,c);return vec2(c,max(m1.y*l0,m2.y*l1));}',
