    return true;
  }
  function readBgUrl(){
    try{ var doc=api.canvas.ownerDocument; var bg=doc.getElementById('vnm-bg'); if(!bg) return '';
      var bi=(TOPW.getComputedStyle?TOPW.getComputedStyle(bg):bg.style).backgroundImage||'';
      var m=bi.match(/url\(["']?([^"')]+)["']?\)/); return m?m[1]:''; }catch(e){ return ''; }
  }
  function loadTex(url){
    if(!url || url===lastUrl || url===failUrl) return; lastUrl=url;
    try{ var img=new (TOPW.Image||Image)(); img.crossOrigin='anonymous';
      img.onload=function(){ try{ gl.bindTexture(gl.TEXTURE_2D,tex); gl.texImage2D(gl.TEXTURE_2D,0,gl.RGBA,gl.RGBA,gl.UNSIGNED_BYTE,img); imgW=img.naturalWidth||img.width||2; imgH=img.naturalHeight||img.height||2; hasTex=1; }catch(e){ hasTex=0; failUrl=url; } };
      img.onerror=function(){ hasTex=0; failUrl=url; };
      img.src=url;
