    if(nowMs-urlT>800){ urlT=nowMs; loadTex(readBgUrl()); }
    var rain = (api.params&&api.params.intensity!=null?api.params.intensity:6)/10;
    var zoom = 100/((api.params&&api.params.size!=null?api.params.size:100));
    gl.useProgram(prog);
    gl.uniform2f(uni.iR, pw, ph);
    gl.uniform1f(uni.iTime, (nowMs-t0)/1000);
    gl.uniform1f(uni.uRain, rain);
    gl.uniform1f(uni.uZoom, zoom);
    gl.uniform2f(uni.uImg, imgW, imgH);
    gl.uniform1f(uni.uHasTex, hasTex);
