    gl.drawArrays(gl.TRIANGLE_STRIP, 0, 4);
    api.ctx.clearRect(0,0,W,H);
    try{ api.ctx.drawImage(glc, 0, 0, W, H); }catch(e){}
  }
  function clear(){ try{ api.ctx.clearRect(0,0,api.width,api.height);}catch(e){} }
  function destroy(){ try{ if(gl&&gl.getExtension){ var l=gl.getExtension('WEBGL_lose_context'); if(l)l.loseContext(); } }catch(e){} }
  return { frame:frame, clear:clear, resize:clear, destroy:destroy };
})
